nros_cpp_ret_t nros_cpp_action_server_publish_feedback(void *handle,
                                                       void *executor_handle,
                                                       const uint8_t (*goal_id)[16],
                                                       const uint8_t *feedback_buf,
                                                       size_t feedback_len);

/**
 * Complete a goal with a result.
 *
 * # Parameters
 * * `handle` — Action server handle.
 * * `executor_handle` — Executor handle from `nros_cpp_init()`.
 * * `goal_id` — 16-byte goal UUID.
 * * `result_buf` — CDR-serialized result data.
 * * `result_len` — Length of result data.
 *
 * # Safety
 * All pointers must be valid.
 */
nros_cpp_ret_t nros_cpp_action_server_complete_goal(void *handle,
                                                    void *executor_handle,
                                                    const uint8_t (*goal_id)[16],
                                                    const uint8_t *result_buf,
                                                    size_t result_len);

/**
 * Iterate over every goal currently live in the arena.
 *
 * Calls `visitor(uuid, status, ctx)` for each entry in the
 * arena's `active_goals`. Status is the raw i8 discriminant of
 * `nros_core::GoalStatus` (0 = Unknown, 1 = Accepted, 2 = Executing,
 * 3 = Canceling, 4 = Succeeded, 5 = Canceled, 6 = Aborted). The arena
 * never stores the original goal CDR payload, so only identity + status
 * are forwarded; users needing the goal bytes should stash them in
 * their own `{uuid → state}` table keyed from `set_goal_callback`.
 *
 * # Safety
 * `handle` must be a valid `CppActionServer` storage pointer.
 * `executor_handle` must point to a valid `CppContext`.
 * `visitor` must be a valid function pointer.
 */
nros_cpp_ret_t nros_cpp_action_server_for_each_active_goal(void *handle,
                                                           void *executor_handle,
                                                           void (*visitor)(const uint8_t (*goal_id)[16],
                                                                           int8_t status,
                                                                           void *ctx),
                                                           void *ctx);

/**
 * Destroy an action server (drop in place, no free).
 *
 * # Safety
 * `storage` must be a valid initialized action server storage, or NULL (no-op).
 */
nros_cpp_ret_t nros_cpp_action_server_destroy(void *storage);

/**
 * Relocate a `CppActionServer` from `old_storage` to `new_storage`.
 *
 * Performs the bitwise move. The C++ `ActionServer<A>` move ctor /
 * move assignment must still call `install_callbacks()` afterwards,
 * because the callback trampolines were registered with the previous
 * `this` as their context and need to be re-registered with the new
 * `this`. This FFI only transfers the runtime state; the re-install
 * step is intentionally left to the C++ side so this function stays
 * free of C++-specific pointer semantics.
 *
 * # Safety
 * See `nros_cpp_publisher_relocate`.
 */
nros_cpp_ret_t nros_cpp_action_server_relocate(void *old_storage, void *new_storage);

/**
 * Create an action client on a node.
 *
 * # Safety
 * All pointer parameters must be valid. `storage` must point to an
 * 8-byte-aligned buffer of at least `CPP_ACTION_CLIENT_OPAQUE_U64S * 8` bytes.
 */
nros_cpp_ret_t nros_cpp_action_client_create(const struct nros_cpp_node_t *node,
                                             const char *action_name,
                                             const char *type_name,
                                             const char *type_hash,
                                             struct nros_cpp_qos_t _qos,
                                             void *storage);

/**
 * Send a goal and receive the generated goal UUID.
 *
 * # Parameters
 * * `handle` — Action client handle.
 * * `goal_buf` — CDR-serialized goal data.
 * * `goal_len` — Length of goal data.
 * * `goal_id_out` — Receives the 16-byte goal UUID.
 *
 * # Safety
 * All pointers must be valid.
 */
nros_cpp_ret_t nros_cpp_action_client_send_goal(void *handle,
                                                const uint8_t *goal_buf,
                                                size_t goal_len,
                                                uint8_t (*goal_id_out)[16]);

/**
 * Get the result for a goal (blocking with timeout).
 *
 * Sends a get_result request and polls for the reply.
 *
 * # Parameters
 * * `handle` — Action client handle.
 * * `executor_handle` — Executor handle for spin_once during polling.
 * * `goal_id` — 16-byte goal UUID.
 * * `result_buf` — Buffer for CDR-serialized result data.
 * * `result_buf_len` — Size of result buffer.
 * * `result_len` — Receives actual result data length.
 *
 * # Safety
 * All pointers must be valid.
 */
nros_cpp_ret_t nros_cpp_action_client_get_result(void *handle,
                                                 void *executor_handle,
                                                 const uint8_t (*goal_id)[16],
                                                 uint8_t *result_buf,
                                                 size_t result_buf_len,
                                                 size_t *result_len);

/**
 * Try to receive feedback (non-blocking).
 *
 * # Parameters
 * * `handle` — Action client handle.
 * * `feedback_buf` — Buffer for CDR-serialized feedback data.
 * * `buf_len` — Size of feedback buffer.
 * * `feedback_len` — Receives actual feedback data length (0 if none available).
 *
 * # Returns
 * `NROS_CPP_RET_OK` on success (check `*feedback_len > 0` for data).
 *
 * # Safety
 * All pointers must be valid.
 */
nros_cpp_ret_t nros_cpp_action_client_try_recv_feedback(void *handle,
                                                        uint8_t *feedback_buf,
                                                        size_t buf_len,
                                                        size_t *feedback_len);

/**
 * Try to receive the goal acceptance response (non-blocking).
 *
 * Returns `NROS_CPP_RET_OK` with serialized `GoalAccept` data if ready,
 * `NROS_CPP_RET_TRY_AGAIN` if not yet available.
 *
 * Output layout: `[goal_id: 16 bytes][accepted: 1 byte]` (17 bytes total).
 *
 * Used by C++ `Future<GoalAccept>` via the `TryRecvFn` interface.
 *
 * # Safety
 * All pointers must be valid. `out_data` must point to `out_capacity` writable bytes.
 */
nros_cpp_ret_t nros_cpp_action_client_try_recv_goal_response(void *handle,
                                                             uint8_t *out_data,
                                                             size_t out_capacity,
                                                             size_t *out_len);

/**
 * Try to receive the result for a pending get_result request (non-blocking).
 *
 * Returns `NROS_CPP_RET_OK` with result data if ready,
 * `NROS_CPP_RET_TRY_AGAIN` if not yet available.
 *
 * Output layout: CDR-serialized result fields (same as `get_result` output).
 *
 * Used by C++ `Future<ResultType>` via the `TryRecvFn` interface.
 *
 * # Safety
 * All pointers must be valid. `out_data` must point to `out_capacity` writable bytes.
 */
nros_cpp_ret_t nros_cpp_action_client_try_recv_result(void *handle,
                                                      uint8_t *out_data,
                                                      size_t out_capacity,
                                                      size_t *out_len);

/**
 * Destroy an action client (drop in place, no free).
 *
 * # Safety
 * `storage` must be a valid initialized action client storage, or NULL (no-op).
 */
nros_cpp_ret_t nros_cpp_action_client_destroy(void *storage);

/**
 * Relocate a `CppActionClient` from `old_storage` to `new_storage`.
 *
 * The action client's async callback context (`options.context`) is
 * user-provided, so it stays valid across the move. Relocation is a
 * straight `ptr::read` + `ptr::write`.
 *
 * # Safety
 * See `nros_cpp_publisher_relocate`.
 */
nros_cpp_ret_t nros_cpp_action_client_relocate(void *old_storage, void *new_storage);

/**
 * Send a goal asynchronously (non-blocking).
 *
 * Uses `send_goal_raw` (zpico_get_start) instead of `send_goal_blocking`.
 * The goal response arrives via the callback registered with
 * `nros_cpp_action_client_register_async`, invoked during `spin_once`.
 *
 * # Safety
 * All pointers must be valid.
 */
nros_cpp_ret_t nros_cpp_action_client_send_goal_async(void *handle,
                                                      const uint8_t *goal_buf,
                                                      size_t goal_len,
                                                      uint8_t (*goal_id_out)[16]);

/**
 * Request a goal result asynchronously (non-blocking).
 *
 * Uses `send_get_result_request` (zpico_get_start) instead of
 * `get_result_blocking`. The result arrives via the result callback
 * registered with `nros_cpp_action_client_register_async`.
 *
 * # Safety
 * All pointers must be valid.
 */
nros_cpp_ret_t nros_cpp_action_client_get_result_async(void *handle, const uint8_t (*goal_id)[16]);

/**
 * Poll action client for pending replies (non-blocking).
 *
 * Checks for goal acceptance reply, feedback, and result reply.
 * Invokes the corresponding callbacks registered via
 * `nros_cpp_action_client_set_callbacks`.
 *
 * Call this in the spin loop after `nros_cpp_spin_once`.
 *
 * # Safety
 * `handle` must be a valid action client storage.
 */
nros_cpp_ret_t nros_cpp_action_client_poll(void *handle);

struct nros_cpp_wake_state_t nros_cpp_wake_state_get_zero_initialized(void);

/**
 * Phase 122.3.c.6.e — wake on subscription rx.
 */
nros_cpp_ret_t nros_cpp_subscription_set_wake_callback(void *storage,
                                                       struct nros_cpp_wake_state_t *state,
                                                       void (*cb)(void*),
                                                       void *ctx);

/**
 * Phase 122.3.c.6.e — wake on service-server rx.
 */
nros_cpp_ret_t nros_cpp_service_server_set_wake_callback(void *storage,
                                                         struct nros_cpp_wake_state_t *state,
                                                         void (*cb)(void*),
                                                         void *ctx);

/**
 * Phase 122.3.c.6.e — wake on service-client reply.
 */
nros_cpp_ret_t nros_cpp_service_client_set_wake_callback(void *storage,
                                                         struct nros_cpp_wake_state_t *state,
                                                         void (*cb)(void*),
                                                         void *ctx);

nros_cpp_ret_t nros_cpp_action_server_set_goal_wake_callback(void *storage,
                                                             struct nros_cpp_wake_state_t *state,
                                                             void (*cb)(void*),
                                                             void *ctx);

nros_cpp_ret_t nros_cpp_action_server_set_cancel_wake_callback(void *storage,
                                                               struct nros_cpp_wake_state_t *state,
                                                               void (*cb)(void*),
                                                               void *ctx);

nros_cpp_ret_t nros_cpp_action_server_set_get_result_wake_callback(void *storage,
                                                                   struct nros_cpp_wake_state_t *state,
                                                                   void (*cb)(void*),
                                                                   void *ctx);

nros_cpp_ret_t nros_cpp_action_client_set_goal_response_wake_callback(void *storage,
                                                                      struct nros_cpp_wake_state_t *state,
                                                                      void (*cb)(void*),
                                                                      void *ctx);

nros_cpp_ret_t nros_cpp_action_client_set_cancel_response_wake_callback(void *storage,
                                                                        struct nros_cpp_wake_state_t *state,
                                                                        void (*cb)(void*),
                                                                        void *ctx);

nros_cpp_ret_t nros_cpp_action_client_set_result_wake_callback(void *storage,
                                                               struct nros_cpp_wake_state_t *state,
                                                               void (*cb)(void*),
                                                               void *ctx);

nros_cpp_ret_t nros_cpp_action_client_set_feedback_wake_callback(void *storage,
                                                                 struct nros_cpp_wake_state_t *state,
                                                                 void (*cb)(void*),
                                                                 void *ctx);

/**
 * Phase 122.3.d — initialize an L1 polling-mode action server.
 *
 * Builds the 5 channels via the node's session and writes the
 * `ActionServerCore` into `storage` (must be at least
 * `NROS_CPP_RAW_ACTION_SERVER_OPAQUE_U64S × 8` bytes,
 * 8-byte-aligned).
 *
 * # Safety
 * All pointers valid; `action_name` / `type_name` / `type_hash`
 * are valid null-terminated strings.
 */
nros_cpp_ret_t nros_cpp_action_server_init_polling(const struct nros_cpp_node_t *node,
                                                   const char *action_name,
                                                   const char *type_name,
                                                   const char *type_hash,
                                                   void *storage);

/**
 * Phase 122.3.d — L1 polling: try to receive a goal request.
 *
 * On success copies the goal payload (CDR-framing-stripped) into
 * `buf`, fills `goal_id_out` (16 bytes) + `sequence_number_out`,
 * returns bytes copied. `0` means no request pending; negative on
 * error.
 */
int32_t nros_cpp_action_server_try_recv_goal_request_raw(void *storage,
                                                         uint8_t *buf,
                                                         size_t buf_len,
                                                         uint8_t (*goal_id_out)[16],
                                                         int64_t *sequence_number_out);

/**
 * Phase 122.3.d — L1 polling: accept a goal received via
 * `try_recv_goal_request_raw`.
 */
nros_cpp_ret_t nros_cpp_action_server_accept_goal_raw(void *storage,
                                                      const uint8_t (*goal_id)[16],
                                                      int64_t sequence_number);

/**
 * Phase 122.3.d — L1 polling: reject a goal.
 */
nros_cpp_ret_t nros_cpp_action_server_reject_goal_raw(void *storage, int64_t sequence_number);

/**
 * Phase 122.3.d — L1 polling: publish feedback.
 */
nros_cpp_ret_t nros_cpp_action_server_publish_feedback_raw(void *storage,
                                                           const uint8_t (*goal_id)[16],
                                                           const uint8_t *feedback_cdr,
                                                           size_t feedback_len);

/**
 * Phase 122.3.d — L1 polling: mark a goal terminal.
 * `status_code`: 4 = Succeeded, 5 = Canceled, 6 = Aborted (matches
 * the `nros_core::GoalStatus` discriminants).
 */
nros_cpp_ret_t nros_cpp_action_server_complete_goal_raw(void *storage,
                                                        const uint8_t (*goal_id)[16],
                                                        int32_t status_code,
                                                        const uint8_t *result_cdr,
                                                        size_t result_len);

/**
 * Phase 122.3.c.6.d / .d — L1 polling: peek a pending
 * cancel-goal request. Writes goal_id + sequence_number +
 * current_status (matches `nros_cpp_goal_status_t` discriminants).
 * Returns `1` on peek, `0` if none pending, negative on error.
 */
int32_t nros_cpp_action_server_try_recv_cancel_request_raw(void *storage,
                                                           uint8_t (*goal_id_out)[16],
                                                           int64_t *sequence_number_out,
                                                           int8_t *current_status_out);

/**
 * Phase 122.3.c.6.d / .d — L1 polling: reply to a cancel-goal
 * request. `return_code` matches `nros_core::CancelResponse`
 * (0 = Ok, 1 = Rejected, 2 = UnknownGoal, 3 = GoalTerminated).
 * `accepted` points to `accepted_count` 16-byte goal-id arrays.
 */
nros_cpp_ret_t nros_cpp_action_server_send_cancel_reply_raw(void *storage,
                                                            int64_t sequence_number,
                                                            int8_t return_code,
                                                            const uint8_t (*accepted)[16],
                                                            size_t accepted_count);

/**
 * Phase 122.3.d — L1 polling: serve a pending get_result query.
 * Returns `1` if served, `0` if none pending, negative on error.
 */
int32_t nros_cpp_action_server_try_handle_get_result_raw(void *storage,
                                                         const uint8_t *default_result_cdr,
                                                         size_t default_result_len);

/**
 * Phase 122.3.d — L1 polling: drop the inline `ActionServerCore`.
 */
nros_cpp_ret_t nros_cpp_action_server_destroy_polling(void *storage);

/**
 * Phase 122.3.d — initialize an L1 polling-mode action client.
 *
 * Builds the 3 service clients + feedback subscriber via the
 * session and writes the `ActionClientCore` into `storage`.
 */
nros_cpp_ret_t nros_cpp_action_client_init_polling(const struct nros_cpp_node_t *node,
                                                   const char *action_name,
                                                   const char *type_name,
                                                   const char *type_hash,
                                                   void *storage);

/**
 * Phase 122.3.d — L1 polling: send a goal. Writes 16-byte UUID
 * into `goal_id_out`.
 */
nros_cpp_ret_t nros_cpp_action_client_send_goal_raw(void *storage,
                                                    const uint8_t *goal_cdr,
                                                    size_t goal_len,
                                                    uint8_t (*goal_id_out)[16]);

/**
 * Phase 122.3.d — L1 polling: try receiving the send_goal RPC reply.
 */
int32_t nros_cpp_action_client_try_recv_goal_response_raw(void *storage,
                                                          uint8_t *buf,
                                                          size_t buf_len);

/**
 * Phase 122.3.d — L1 polling: send a get_result request.
 */
nros_cpp_ret_t nros_cpp_action_client_send_get_result_request_raw(void *storage,
                                                                  const uint8_t (*goal_id)[16]);

/**
 * Phase 122.3.d — L1 polling: try receiving the get_result reply.
 */
int32_t nros_cpp_action_client_try_recv_result_raw(void *storage, uint8_t *buf, size_t buf_len);

/**
 * Phase 122.3.d — L1 polling: send a cancel request.
 */
nros_cpp_ret_t nros_cpp_action_client_send_cancel_request_raw(void *storage,
                                                              const uint8_t (*goal_id)[16]);

/**
 * Phase 122.3.d / .c.6.c — L1 polling: try receiving the cancel
 * RPC reply.
 */
int32_t nros_cpp_action_client_try_recv_cancel_response_raw(void *storage,
                                                            uint8_t *buf,
                                                            size_t buf_len);

/**
 * Phase 122.3.d — L1 polling: try receiving feedback. Writes
 * goal_id_out + bytes copied.
 */
int32_t nros_cpp_action_client_try_recv_feedback_raw(void *storage,
                                                     uint8_t *buf,
                                                     size_t buf_len,
                                                     uint8_t (*goal_id_out)[16]);

/**
 * Phase 122.3.d — L1 polling: drop the inline `ActionClientCore`.
 */
nros_cpp_ret_t nros_cpp_action_client_destroy_polling(void *storage);

/**
 * Phase 115.D — register a custom transport vtable. C++-side entry
 * for `nros::set_custom_transport`.
 *
 * # Safety
 *
 * `ops`, when non-NULL, must point to a valid `nros_cpp_transport_ops_t`.
 * The four function pointers must follow the threading contract
 * documented in `<nros/transport.hpp>`.
 */
nros_cpp_ret_t nros_cpp_set_custom_transport(const struct nros_cpp_transport_ops_t *ops);

/**
 * Phase 115.D — clear any previously-registered transport.
 */
nros_cpp_ret_t nros_cpp_clear_custom_transport(void);

/**
 * Phase 115.D — return `1` if a transport is registered, `0`
 * otherwise. Returned as `nros_cpp_ret_t` for ABI parity with the
 * other entries.
 */
nros_cpp_ret_t nros_cpp_has_custom_transport(void);

/**
 * Issue a service-client raw-CDR request from a tick body and block on
 * the reply (Phase 212.M-F.4.c).
 *
 * Mirrors `nros::TickCtx::call_raw` (Rust). The C++ side passes the
 * opaque per-tick handle it received from the generated runtime as
 * `tick_ctx`, plus the request CDR bytes + a response buffer the runtime
 * will fill with the reply CDR. On success `*response_len_out` carries
 * the response length in bytes; on error it is left untouched.
 *
 * # Parameters
 * * `tick_ctx` — opaque per-tick context handle. Provided by the
 *   generated runtime (M-F.4.a, not yet shipped); pass any non-null
 *   pointer for forward-compat smoke tests — the call will still fail
 *   with `NROS_CPP_RET_ERROR` until the runtime backs the handle.
 * * `service_entity` — stable entity id of the service client (NUL-term).
 * * `service_entity_len` — `service_entity` byte length (excluding NUL).
 * * `request_cdr` / `request_len` — request CDR bytes.
 * * `response_buf` / `response_buf_cap` — caller-owned reply buffer.
 * * `response_len_out` — out-param: response length on success.
 *
 * # Safety
 * All non-NULL pointers must be valid for the indicated lengths. NULL
 * `service_entity`, NULL `request_cdr` with non-zero `request_len`,
 * NULL `response_buf` with non-zero `response_buf_cap`, or NULL
 * `response_len_out` all yield `NROS_CPP_RET_INVALID_ARGUMENT`.
 */
nros_cpp_ret_t nros_cpp_tick_ctx_call_raw(void *tick_ctx,
                                          const uint8_t *service_entity,
                                          size_t service_entity_len,
                                          const uint8_t *request_cdr,
                                          size_t request_len,
                                          uint8_t *response_buf,
                                          size_t response_buf_cap,
                                          size_t *response_len_out);

/**
 * Kick an action-client goal from a tick body (Phase 212.M-F.4.c).
 *
 * Mirrors `nros::TickCtx::send_goal_raw` (Rust). The server-side
 * accept stamps the assigned [`GoalId`]; this call returns that id in
 * `goal_id_out` (16 bytes). Result + feedback streams arrive via
 * callback dispatch — not this method.
 *
 * # Parameters
 * * `tick_ctx` — opaque per-tick context handle (see `call_raw`).
 * * `action_entity` / `action_entity_len` — stable action-client entity id.
 * * `goal_cdr` / `goal_len` — goal request CDR bytes.
 * * `goal_id_out` — 16-byte buffer; receives the server-stamped goal id.
 *
 * # Safety
 * All non-NULL pointers must be valid for the indicated lengths. NULL
 * `action_entity`, NULL `goal_cdr` with non-zero `goal_len`, or NULL
 * `goal_id_out` yield `NROS_CPP_RET_INVALID_ARGUMENT`.
 */
nros_cpp_ret_t nros_cpp_tick_ctx_send_goal_raw(void *tick_ctx,
                                               const uint8_t *action_entity,
                                               size_t action_entity_len,
                                               const uint8_t *goal_cdr,
                                               size_t goal_len,
                                               uint8_t (*goal_id_out)[16]);

